patches.patch:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}
body {
    min-height: 100vh;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
    background: linear-gradient(120deg, #e0f7fa, #f3e5f5, #fff3e0);
    background-size: 400% 400%;
    animation: bgFlow 8s ease infinite;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "PingFang SC", "Hiragino Sans GB", "Microsoft YaHei", sans-serif;
}
#particle-bg {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 0;
    pointer-events: none;
}
.text-container {
    position: relative;
    z-index: 10;
    font-size: clamp(3rem, 12vw, 10rem);
    font-weight: 700;
    background: linear-gradient(90deg, #2196f3, #9c27b0, #ff9800, #2196f3);
    background-size: 300% 100%;
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
    animation: textFlow 5s linear infinite, fadeIn 2s ease forwards, float 3s ease-in-out infinite;
    cursor: default;
    user-select: none;
    transition: transform 0.3s ease, filter 0.3s ease;
}
.text-container:hover {
    transform: scale(1.05);
    filter: drop-shadow(0 0 30px rgba(156, 39, 176, 0.6));
}
@keyframes bgFlow {
    0% { background-position: 0% 50%; }
    50% { background-position: 100% 50%; }
    100% { background-position: 0% 50%; }
}
@keyframes textFlow {
    0% { background-position: 0% 50%; }
    100% { background-position: 300% 50%; }
}
@keyframes fadeIn {
    from { opacity: 0; transform: translateY(30px); }
    to { opacity: 1; transform: translateY(0); }
}
@keyframes float {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-10px); }
}
@media (prefers-color-scheme: dark) {
    body {
        background: linear-gradient(120deg, #0f172a, #1e1b4b, #312e81);
        background-size: 400% 400%;
    }
    .text-container {
        background: linear-gradient(90deg, #60a5fa, #c084fc, #fbbf24, #60a5fa);
        background-size: 300% 100%;
        -webkit-background-clip: text;
        background-clip: text;
    }
    .text-container:hover {
        filter: drop-shadow(0 0 30px rgba(192, 132, 252, 0.6));
    }
}

const canvas = document.getElementById('particle-bg');
const ctx = canvas.getContext('2d');
let particles = [];
let isDarkMode = window.matchMedia('(prefers-color-scheme: dark)').matches;

function resizeCanvas() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    initParticles();
}

function initParticles() {
    particles = [];
    const count = Math.min(20, Math.floor(window.innerWidth * window.innerHeight / 30000));
    for (let i = 0; i < count; i++) {
        particles.push({
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height,
            size: Math.random() * 3 + 1,
            speedX: (Math.random() - 0.5) * 0.5,
            speedY: (Math.random() - 0.5) * 0.5,
            opacity: Math.random() * 0.3 + 0.1
        });
    }
}

function drawParticles() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    const color = isDarkMode ? '255, 255, 255' : '0, 0, 0';
    particles.forEach(p => {
        ctx.fillStyle = `rgba(${color}, ${p.opacity})`;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fill();
        p.x += p.speedX;
        p.y += p.speedY;
        if (p.x < 0 || p.x > canvas.width) p.speedX *= -1;
        if (p.y < 0 || p.y > canvas.height) p.speedY *= -1;
    });
    requestAnimationFrame(drawParticles);
}

window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', e => {
    isDarkMode = e.matches;
});

new ResizeObserver(resizeCanvas).observe(document.body);
resizeCanvas();
drawParticles();
